from dataclasses import dataclass
from datetime import datetime, timedelta
from enum import IntEnum


class Severity(IntEnum):
    P0 = 0; P1 = 1; P2 = 2; P3 = 3


OBSERVATION_WINDOWS = {
    Severity.P0: timedelta(minutes=30),
    Severity.P1: timedelta(minutes=45),
    Severity.P2: timedelta(minutes=60),
    Severity.P3: timedelta(hours=2),
}


@dataclass
class DeEscalationGateResult:
    passed: bool
    failed_gates: list[str]
    window_remaining: timedelta


def check_de_escalation_gates(
    current_severity: Severity,
    mitigation_declared_at: datetime,
    signals: dict,
) -> DeEscalationGateResult:
    """
    Returns whether the IC may de-escalate or close the incident.

    signals keys: error_rate_pct, latency_ok, quality_score_pct_drop,
                  safety_cleared, no_new_reports_min, root_cause_known
    """
    now = datetime.utcnow()
    window = OBSERVATION_WINDOWS[current_severity]
    elapsed = now - mitigation_declared_at
    if elapsed < window:
        return DeEscalationGateResult(
            passed=False,
            failed_gates=[f"Observation window not complete ({elapsed} / {window})"],
            window_remaining=window - elapsed,
        )

    failed = []
    if current_severity == Severity.P0:
        if not signals.get("safety_cleared"):
            failed.append("Safety/privacy signal not cleared")
        if signals.get("error_rate_pct", 100) > 0.5:
            failed.append("Error rate above baseline")

    elif current_severity == Severity.P1:
        if signals.get("error_rate_pct", 100) >= 1.0:
            failed.append("Error rate >= 1%")
        if not signals.get("latency_ok"):
            failed.append("Latency still above SLA")

    elif current_severity == Severity.P2:
        if signals.get("quality_score_pct_drop", 100) > 5.0:
            failed.append("Quality score >5% below baseline")
        if signals.get("no_new_reports_min", 0) < 30:
            failed.append("New customer reports within last 30 min")

    elif current_severity == Severity.P3:
        if not signals.get("root_cause_known"):
            failed.append("Root cause not yet identified")

    return DeEscalationGateResult(
        passed=len(failed) == 0,
        failed_gates=failed,
        window_remaining=timedelta(0),
    )
